	if !isValidHost(host) {
		return 0, fmt.Errorf("invalid host provided")
	}

	// Construct the ping command
	// -c count: number of packets to send
	// -W timeout: timeout in seconds per packet (Linux)
	// -w timeout: total timeout in seconds (macOS)
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows uses -n for count and -w for timeout in milliseconds
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), "-w", "2000", host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), "-W", "2", host)
	}

	// Execute the command and capture the output
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	// Parse the output to find the average latency
	// Common ping output includes a line like:
	// "rtt min/avg/max/mdev = 20.123/21.456/22.789/0.567 ms"
	// We'll use a regex to extract the average value.
	regex := regexp.MustCompile(`rtt\s+min/avg/max/mdev\s+=\s+[^/]+/([^/]+)/[^/]+/[^/]+\s+ms`)
	matches := regex.FindStringSubmatch(string(output))

	if len(matches) < 2 {
		// Fallback: try to find any number followed by 'ms' in the last line
		lines := strings.Split(string(output), "\n")
