				numMatches := numRegex.FindStringSubmatch(line)
				if len(numMatches) > 1 {
					val, err := strconv.ParseFloat(numMatches[1], 64)
					if err == nil {
						return val, nil
					}
				}
			}
		}
		return 0, fmt.Errorf("could not parse average latency from ping output")
	}

