// MeasureLatency pings a host a specified number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	// Validate host to prevent command injection
	if !isValidHost(host) {
		return 0, fmt.Errorf("invalid host: contains invalid characters")
	}

	// Construct the ping command
	// -c count: number of packets to send
	// -q: quiet output (only summary lines)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-q", host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// If the ping command fails (e.g., host unreachable), return the error
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, output)
	}

	// Parse the output to find the average latency
	// The last line of ping -q output usually looks like:
	// "rtt min/avg/max/mdev = 10.123/15.456/20.789/2.345 ms"
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	if len(lines) == 0 {
		return 0, fmt.Errorf("no output from ping command")
	}

	// Look for the line containing the rtt statistics
	var avgLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt ") && strings.Contains(line, "min/avg/max/mdev") {
			avgLine = line
			break
		}
	}

	if avgLine == "" {
		return 0, fmt.Errorf("could not find rtt statistics in ping output")
	}

	// Extract the average value using a regular expression
	// Match pattern like "15.456" in "rtt min/avg/max/mdev = 10.123/15.456/20.789/2.345 ms"
	re := regexp.MustCompile(`\d+\.?\d*/(\d+\.?\d*)/\d+\.?\d*/\d+\.?\d*`)
	matches := re.FindStringSubmatch(avgLine)
	if len(matches) < 2 {
		return 0, fmt.Errorf("could not parse average latency from output: %s", avgLine)
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %w", err)
	}

	return avg, nil
}

// isValidHost validates the host parameter to prevent command injection
func isValidHost(host string) bool {
	// Allow only alphanumeric characters, hyphens, periods, and colons (for IPv6)
	// This is a basic validation; in production, you might want stricter validation
	validPattern := regexp.MustCompile(`^[a-zA-Z0-9.\-:]+$`)
	if !validPattern.MatchString(host) {
		return false
	}

	// Check for command injection attempts
	if strings.ContainsAny(host, ";|&$()") {
		return false
	}

	// Ensure host is not empty
	if host == "" {
		return false
	}

	return true
}

func main() {
	// Example usage
